`esp_http_client` handles connect, redirect, and chunked decoding. `event_handler` is fed each phase.

```c
#include "esp_log.h"
#include "esp_http_client.h"
#include "esp_crt_bundle.h"

static const char *TAG = "http";

static esp_err_t on_event(esp_http_client_event_t *evt) {
    if (evt->event_id == HTTP_EVENT_ON_DATA) {
        ESP_LOGI(TAG, "%.*s", evt->data_len, (char*)evt->data);
    }
    return ESP_OK;
}

void http_get(void) {
    esp_http_client_config_t cfg = {
        .url = "https://example.com",
        .event_handler = on_event,
        .crt_bundle_attach = esp_crt_bundle_attach,
    };
    esp_http_client_handle_t c = esp_http_client_init(&cfg);
    esp_http_client_perform(c);
    esp_http_client_cleanup(c);
}
```

Required components: `esp_http_client`, `esp-tls` (with `esp_crt_bundle` enabled in menuconfig). Call `http_get()` from `app_main` after WiFi has an IP.

`esp_mqtt_client_start` is non-blocking; events arrive on the registered handler. Loop in `app_main` does the periodic publish.

```c
#include <stdio.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_log.h"
#include "mqtt_client.h"

static const char *TAG = "mqtt";
static esp_mqtt_client_handle_t client;

static void on_mqtt(void *arg, esp_event_base_t base, int32_t id, void *data) {
    if (id == MQTT_EVENT_CONNECTED) ESP_LOGI(TAG, "connected");
}

void app_main(void) {
    // assume WiFi already up (handled elsewhere in your project)
    esp_mqtt_client_config_t cfg = {
        .broker.address.uri = "mqtt://broker.local",
    };
    client = esp_mqtt_client_init(&cfg);
    esp_mqtt_client_register_event(client, ESP_EVENT_ANY_ID, on_mqtt, NULL);
    esp_mqtt_client_start(client);

    while (true) {
        esp_mqtt_client_publish(client, "demo", "hello", 0, 0, 0);
        vTaskDelay(pdMS_TO_TICKS(10000));
    }
}
```

