ISRs in IDF must be in IRAM (`IRAM_ATTR`). `xQueueSendFromISR` is the safe handoff to a task.

```c
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "freertos/queue.h"
#include "driver/gpio.h"
#include "esp_log.h"

#define BTN_PIN GPIO_NUM_0

static QueueHandle_t evt_q;

static void IRAM_ATTR isr(void *arg) {
    uint32_t pin = (uint32_t)arg;
    BaseType_t hp = pdFALSE;
    xQueueSendFromISR(evt_q, &pin, &hp);
    if (hp) portYIELD_FROM_ISR();
}

static void task(void *arg) {
    uint32_t pin;
    while (true) {
        if (xQueueReceive(evt_q, &pin, portMAX_DELAY)) {
            ESP_LOGI("btn", "edge on GPIO%lu", (unsigned long)pin);
        }
    }
}

void app_main(void) {
    evt_q = xQueueCreate(8, sizeof(uint32_t));
    xTaskCreate(task, "btn-task", 2048, NULL, 10, NULL);

    gpio_config_t cfg = {
        .pin_bit_mask = 1ULL << BTN_PIN,
        .mode = GPIO_MODE_INPUT,
        .pull_up_en = GPIO_PULLUP_ENABLE,
        .intr_type = GPIO_INTR_NEGEDGE,
    };
    gpio_config(&cfg);
    gpio_install_isr_service(0);
    gpio_isr_handler_add(BTN_PIN, isr, (void*)BTN_PIN);
}
```

