`esp_adc/adc_oneshot.h` is the v5+ replacement for the legacy `adc1_get_raw` API.

```c
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_log.h"
#include "esp_adc/adc_oneshot.h"

static const char *TAG = "adc";

void app_main(void) {
    adc_oneshot_unit_handle_t unit;
    adc_oneshot_unit_init_cfg_t unit_cfg = { .unit_id = ADC_UNIT_1 };
    adc_oneshot_new_unit(&unit_cfg, &unit);

    adc_oneshot_chan_cfg_t ch_cfg = {
        .atten = ADC_ATTEN_DB_12,
        .bitwidth = ADC_BITWIDTH_DEFAULT,
    };
    adc_oneshot_config_channel(unit, ADC_CHANNEL_0, &ch_cfg);

    while (true) {
        int raw = 0;
        adc_oneshot_read(unit, ADC_CHANNEL_0, &raw);
        ESP_LOGI(TAG, "raw=%d", raw);
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}
```

