The new bus-based driver (v5.2+) replaces the legacy `i2c.h`. You add a device handle to the bus and use `i2c_master_transmit_receive` for register reads.

```c
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "driver/i2c_master.h"
#include "esp_log.h"

#define I2C_PORT     I2C_NUM_0
#define SDA_PIN      8
#define SCL_PIN      9
#define BME_ADDR     0x76

static const char *TAG = "bme";

void app_main(void) {
    i2c_master_bus_config_t bus_cfg = {
        .clk_source = I2C_CLK_SRC_DEFAULT,
        .i2c_port = I2C_PORT,
        .scl_io_num = SCL_PIN,
        .sda_io_num = SDA_PIN,
        .glitch_ignore_cnt = 7,
    };
    i2c_master_bus_handle_t bus;
    i2c_new_master_bus(&bus_cfg, &bus);

    i2c_device_config_t dev_cfg = {
        .dev_addr_length = I2C_ADDR_BIT_LEN_7,
        .device_address = BME_ADDR,
        .scl_speed_hz = 400000,
    };
    i2c_master_dev_handle_t dev;
    i2c_master_bus_add_device(bus, &dev_cfg, &dev);

    while (true) {
        uint8_t reg = 0xD0; // chip id
        uint8_t id = 0;
        i2c_master_transmit_receive(dev, &reg, 1, &id, 1, 100);
        ESP_LOGI(TAG, "chip id = 0x%02X", id);
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}
```

