NVS keys are namespace-scoped. `nvs_open` opens the namespace, `nvs_get_i32`/`nvs_set_i32` round-trip the value.

```c
#include "esp_log.h"
#include "nvs_flash.h"
#include "nvs.h"

static const char *TAG = "nvs";

void app_main(void) {
    ESP_ERROR_CHECK(nvs_flash_init());
    nvs_handle_t h;
    ESP_ERROR_CHECK(nvs_open("app", NVS_READWRITE, &h));

    int32_t boots = 0;
    nvs_get_i32(h, "boots", &boots);  // missing key -> stays 0
    boots++;
    ESP_ERROR_CHECK(nvs_set_i32(h, "boots", boots));
    ESP_ERROR_CHECK(nvs_commit(h));
    nvs_close(h);

    ESP_LOGI(TAG, "boot #%ld", boots);
}
```

